[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private readonly IWebHostEnvironment _environment;
    private readonly IFileValidationService _validationService;

    // Size limits
    private const long AvatarMaxSize = 2 * 1024 * 1024;    // 2 MB
    private const long DocumentMaxSize = 10 * 1024 * 1024;  // 10 MB

    public FileUploadController(IWebHostEnvironment environment)
    {
        _environment = environment;
        _validationService = new FileValidationService();
    }

    [HttpPost("avatar")]
    [RequestSizeLimit(2 * 1024 * 1024)]
    public async Task<IActionResult> UploadAvatar(IFormFile? file)
    {
        return await ProcessUpload(file, "avatar", AvatarMaxSize);
    }

    [HttpPost("document")]
    [RequestSizeLimit(10 * 1024 * 1024)]
    public async Task<IActionResult> UploadDocument(IFormFile? file)
    {
        return await ProcessUpload(file, "document", DocumentMaxSize);
    }

    private async Task<IActionResult> ProcessUpload(IFormFile? file, string uploadType, long maxSize)
    {
        // 1. Null/empty check
        if (file == null || file.Length == 0)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "No file provided or file is empty."
            });
        }

        // 2. Size check (defense in depth alongside RequestSizeLimit)
        if (file.Length > maxSize)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File exceeds maximum allowed size of {maxSize / (1024 * 1024)} MB."
            });
        }

        // 3. Sanitize the original file name — strip path info to prevent directory traversal
        var originalFileName = Path.GetFileName(file.FileName);
        if (string.IsNullOrWhiteSpace(originalFileName))
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "Invalid file name."
            });
        }

        // 4. Check for null bytes or suspicious characters in the file name
        if (originalFileName.IndexOfAny(Path.GetInvalidFileNameChars()) >= 0 ||
            originalFileName.Contains('\0'))
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "File name contains invalid characters."
            });
        }

        // 5. Reject double extensions (e.g., "file.php.jpg" or "file.aspx.png")
        var dangerousExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".exe", ".bat", ".cmd", ".com", ".msi", ".dll", ".scr", ".ps1",
            ".vbs", ".js", ".wsh", ".wsf", ".asp", ".aspx", ".php", ".jsp",
            ".cgi", ".pl", ".py", ".rb", ".sh", ".bash", ".htaccess", ".config"
        };

        // Check all "extensions" in the filename (split by dots)
        var nameParts = originalFileName.Split('.');
        if (nameParts.Length > 2)
        {
            // Check intermediate extensions for dangerous ones
            for (int i = 1; i < nameParts.Length - 1; i++)
            {
                var intermediateExt = "." + nameParts[i];
                if (dangerousExtensions.Contains(intermediateExt))
                {
                    return BadRequest(new FileUploadResult
                    {
                        Success = false,
                        ErrorMessage = "File name contains a suspicious extension pattern."
                    });
                }
            }
        }

        var extension = Path.GetExtension(originalFileName);

        // 6. Extension whitelist check
        if (!_validationService.IsAllowedExtension(originalFileName, uploadType))
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File extension '{extension}' is not allowed for {uploadType} uploads."
            });
        }

        // 7. Content-Type whitelist check
        if (!_validationService.IsAllowedContentType(file.ContentType, uploadType))
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"Content type '{file.ContentType}' is not allowed for {uploadType} uploads."
            });
        }

        // 8. Magic byte / file signature validation
        using var memoryStream = new MemoryStream();
        await file.CopyToAsync(memoryStream);

        if (!_validationService.ValidateFileSignature(memoryStream, extension))
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "File content does not match the declared file type."
            });
        }

        // 9. Build a safe storage path outside of directly executable directories
        //    Store under wwwroot/uploads/{uploadType}/ with a GUID-based name
        var uploadsRoot = Path.Combine(_environment.WebRootPath, "uploads", uploadType);
        Directory.CreateDirectory(uploadsRoot);

        // Generate a safe, non-guessable file name — preserve only the validated extension
        var safeFileName = $"{Guid.NewGuid():N}{extension.ToLowerInvariant()}";
        var fullPath = Path.Combine(uploadsRoot, safeFileName);

        // 10. Final path traversal guard: ensure resolved path is within the uploads directory
        var resolvedPath = Path.GetFullPath(fullPath);
        var resolvedUploadsRoot = Path.GetFullPath(uploadsRoot);
        if (!resolvedPath.StartsWith(resolvedUploadsRoot, StringComparison.OrdinalIgnoreCase))
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "Invalid file path detected."
            });
        }

        // 11. Write the file from the already-buffered memory stream
        memoryStream.Position = 0;
        using (var fileStream = new FileStream(resolvedPath, FileMode.Create, FileAccess.Write))
        {
            await memoryStream.CopyToAsync(fileStream);
        }

        // 12. Return the relative URL path (not the physical path)
        var relativePath = $"/uploads/{uploadType}/{safeFileName}";

        return Ok(new FileUploadResult
